async (params, browser) => {
  // Open exchanges ranking page
  await browser.open('https://coinmarketcap.com/rankings/exchanges/')

  // Wait for exchanges table to load
  await browser.waitForSelector('table tbody tr', 15000)

  // Let table render
  await browser.wait(2500)

  // Scroll to load more exchanges
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract exchange rankings
  const exchanges_data = await browser.evaluate(`var limit = parseInt('' + params.limit + '') || 20; var exchanges = []; var rows = document.querySelectorAll('table tbody tr'); for (var i = 0; i < Math.min(rows.length, limit); i++) { var row = rows[i]; var cells = row.querySelectorAll('td'); if (cells.length < 4) continue; var rank = cells[0] ? cells[0].textContent.trim() : String(i + 1); var nameCell = cells[1] || cells[2]; var linkEl = nameCell ? nameCell.querySelector('a[href*="/exchanges/"]') : null; var nameEl = linkEl || (nameCell ? nameCell.querySelector('a, p') : null); var volumeCell = cells[2] || cells[3]; var volume = volumeCell ? volumeCell.textContent.trim() : ''; var marketsCell = cells[3] || cells[4]; var markets = marketsCell ? marketsCell.textContent.trim() : ''; var coinsCell = cells[4] || cells[5]; var coins = coinsCell ? coinsCell.textContent.trim() : ''; var scoreCell = cells[5] || cells[6]; var score = scoreCell ? scoreCell.textContent.trim() : ''; exchanges.push({ rank: rank, name: nameEl ? nameEl.textContent.trim() : '', volume_24h: volume, markets: markets, coins: coins, exchange_score: score, url: linkEl ? linkEl.href : '' }); } return { scraped_count: exchanges.length, exchanges: exchanges }`)

  return exchanges_data
}
